import { SITE } from "@/lib/constants";
import { SECTION_ORDER, orderedPages } from "@/lib/docs-content";

// /docs/llms.txt — section-scoped navigation index. Lists every documentation
// page grouped by top-level section so an agent can fetch a focused map of the
// docs area without pulling the whole site (/llms.txt) or all content
// (/llms-full.txt). A static route segment takes precedence over the
// app/docs/[[...slug]] catch-all.
export const revalidate = false;

const TITLE: Record<string, string> = {
	"getting-started": "Getting Started",
	foundations: "Concepts",
	memory: "Memory",
	analytics: "Analytics",
	guides: "Guides",
	cookbook: "Cookbook",
	skills: "Skills",
	agents: "Agents",
	hooks: "Hooks",
	troubleshooting: "Troubleshooting",
	showcase: "Showcase",
	reference: "Reference",
	changelog: "Changelog",
};

export function GET() {
	const bySection = new Map<string, string[]>();
	for (const page of orderedPages()) {
		const section = page.slugs[0] ?? "other";
		const line = `- [${page.data.title}](${page.url})${page.data.description ? `: ${page.data.description}` : ""}`;
		const list = bySection.get(section) ?? [];
		list.push(line);
		bySection.set(section, list);
	}

	const lines = [
		`# ${SITE.name} Documentation`,
		"",
		"> Full page index grouped by section. Append `.md` to any page URL for raw Markdown.",
		"",
	];

	const sections = [
		...SECTION_ORDER.filter((s) => bySection.has(s)),
		...[...bySection.keys()].filter(
			(s) => !SECTION_ORDER.includes(s as (typeof SECTION_ORDER)[number]),
		),
	];

	for (const section of sections) {
		lines.push(`## ${TITLE[section] ?? section}`, "");
		lines.push(...(bySection.get(section) ?? []));
		lines.push("");
	}

	return new Response(lines.join("\n"), {
		headers: {
			"Content-Type": "text/plain; charset=utf-8",
			"Cache-Control": "public, max-age=3600",
		},
	});
}
